proof fn phi_1_interp_aux_key_from_entry(d: Directory, va: nat)
    requires
        d.inv(),
        d.interp_aux(0).contains_key(va),
    ensures
        exists|i: nat| #![auto] 0 <= i < d.num_entries() && d.interp_of_entry(i).contains_key(va),
{
    d.lemma_interp_aux_contains_implies_interp_of_entry_contains(0);
}

proof fn phi_2_interp_aux_pair_from_entry(d: Directory, va: nat, pte: PTE)
    requires
        d.inv(),
        d.interp_aux(0).contains_pair(va, pte),
    ensures
        exists|i: nat| #![auto] 0 <= i < d.num_entries() && d.interp_of_entry(i).contains_pair(va, pte),
{
    d.lemma_interp_aux_contains_implies_interp_of_entry_contains(0);
}

proof fn phi_5_interp_aux_superset_of_entry(d: Directory, i: nat, va: nat, pte: PTE)
    requires
        d.inv(),
        i < d.entries.len(),
        d.interp_of_entry(i).contains_pair(va, pte),
    ensures
        d.interp_aux(0).contains_key(va),
{
    d.lemma_interp_aux_contains_implies_interp_of_entry_contains(0);
}
